import React, { useState, useEffect, useContext, useCallback } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldCheck, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    // --- STATE MANAGEMENT ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    // --- 1. DATA INITIALIZATION ---
    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    initializeStocks(res.data[0].holdings);
                }
            } catch (err) {
                console.error("VAULT_OFFLINE: UNABLE_TO_SYNC");
            }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            
            setStocks(tickers.map(t => ({
                ticker: t,
                price: Math.floor(Math.random() * 1500) + 400,
                change: 0.00
            })));
        } catch (e) {
            setStocks([]);
        }
    };

    // --- 2. LIVE PULSE LOGIC ---
    useEffect(() => {
        if (!token) return;

        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            // Logic: Simulate volatility linked to server heartbeat
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 6.5;
                return {
                    ...s,
                    price: parseFloat((s.price + move).toFixed(2)),
                    change: parseFloat(move.toFixed(2))
                };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    // --- 3. NAVIGATION LOGIC ---
    const navigate = (direction) => {
        let newIndex = currentIndex + direction;
        if (newIndex >= 0 && newIndex < history.length) {
            setCurrentIndex(newIndex);
            initializeStocks(history[newIndex].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div className="reveal-node" style={pageWrapper}>
            {/* ── TOP BAR: NAVIGATION & STATUS ── */}
            <div style={headerContainer}>
                <div style={navRow}>
                    <button 
                        onClick={() => navigate(1)} 
                        disabled={currentIndex === history.length - 1}
                        style={navBtn(currentIndex === history.length - 1)}
                    >
                        <ChevronLeft size={18}/> PREV_NODE
                    </button>

                    <div style={nodeTitleBox}>
                        <Box size={14} color="#10b981" />
                        <span style={nodeText}>
                            {activeNode ? activeNode.goal : 'INITIALIZING_CORE...'}
                        </span>
                        <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                    </div>

                    <button 
                        onClick={() => navigate(-1)} 
                        disabled={currentIndex === 0}
                        style={navBtn(currentIndex === 0)}
                    >
                        NEXT_NODE <ChevronRight size={18}/>
                    </button>
                </div>

                <div style={secondaryHeader}>
                    <div style={statusBadge(isConnected)}>
                        <Activity size={12} />
                        {isConnected ? 'UPLINK_STABLE' : 'UPLINK_DISCONNECTED'}
                    </div>
                    <div style={auditBadge}>
                        <ShieldCheck size={12} /> RISK_EXPOSURE: {activeNode?.risk_score || 0}%
                    </div>
                </div>
            </div>

            {/* ── MAIN CONTENT: LIVE TICKERS ── */}
            <div style={scrollArea}>
                <div style={gridStyle}>
                    {stocks.map((stock, i) => (
                        <div key={i} style={stockCard(stock.change >= 0)}>
                            <div style={cardHeader}>
                                <span style={tickerName}>{stock.ticker}</span>
                                <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                            </div>
                            <div style={priceContainer}>
                                <span style={priceLabel}>MARKET_VALUE</span>
                                <span style={priceText}>₹{stock.price.toLocaleString()}</span>
                            </div>
                            <div style={changeRow(stock.change >= 0)}>
                                {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                <span>{stock.change >= 0 ? '+' : ''}{stock.change}%</span>
                            </div>
                        </div>
                    ))}
                    {stocks.length === 0 && (
                        <div style={emptyState}>AWAITING_PORTFOLIO_NODE_INDEX...</div>
                    )}
                </div>
            </div>

            <style>{`
                .reveal-node { animation: fadeIn 0.4s ease-out; }
                @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
            `}</style>
        </div>
    );
};

/* --- Visual Styles (No Padding, Edge-to-Edge Logic) --- */
const pageWrapper = { height: 'calc(100vh - 70px)', width: '100%', background: '#07080a', display: 'flex', flexDirection: 'column', overflow: 'hidden' };

const headerContainer = { padding: '1rem 2rem', background: '#0a0b0e', borderBottom: '1px solid #1a1d23', width: '100%', boxSizing: 'border-box' };
const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' };
const navBtn = (disabled) => ({ background: 'none', border: 'none', color: disabled ? '#444' : '#10b981', cursor: disabled ? 'default' : 'pointer', fontSize: '0.65rem', fontWeight: 800, fontFamily: 'monospace', display: 'flex', alignItems: 'center', gap: '5px', opacity: disabled ? 0.4 : 1 });

const nodeTitleBox = { display: 'flex', alignItems: 'center', gap: '15px', background: '#111318', padding: '8px 16px', borderRadius: '4px', border: '1px solid #1a1d23', maxWidth: '60%' };
const nodeText = { fontSize: '0.75rem', fontWeight: 700, color: '#fff', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };
const counterTag = { fontSize: '0.6rem', color: '#10b981', background: 'rgba(16,185,129,0.1)', padding: '2px 6px', borderRadius: '4px' };

const secondaryHeader = { display: 'flex', gap: '1.5rem', alignItems: 'center' };
const statusBadge = (online) => ({ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.55rem', fontWeight: 900, color: online ? '#10b981' : '#ef4444', fontFamily: 'monospace' });
const auditBadge = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.55rem', fontWeight: 900, color: '#666', fontFamily: 'monospace' };

const scrollArea = { flex: 1, padding: '1.5rem 2rem', overflowY: 'auto', width: '100%', boxSizing: 'border-box' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '1.2rem' };

const stockCard = (up) => ({ padding: '1.4rem', background: '#111318', border: '1px solid #1a1d23', borderRadius: '8px', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}`, transition: 'all 0.3s ease' });
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const tickerName = { fontSize: '0.8rem', fontWeight: 900, color: '#10b981', fontFamily: 'monospace' };
const priceContainer = { display: 'flex', flexDirection: 'column', marginBottom: '0.8rem' };
const priceLabel = { fontSize: '0.5rem', color: '#444', fontWeight: 800, letterSpacing: '0.1em' };
const priceText = { fontSize: '1.8rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeRow = (up) => ({ color: up ? '#10b981' : '#ef4444', fontSize: '0.8rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px' });

const emptyState = { textAlign: 'center', padding: '5rem', color: '#444', fontFamily: 'monospace', fontSize: '0.75rem' };

export default LiveMarketPage;
